    /**
     * Lists a source's favorites, most recently added first.
     *
     * # Errors
     * Returns [`ApiError::StorageCorrupt`] on a query failure.
     */
    suspend fun `list`(`sourceId`: kotlin.Long): List<Favorite>
    
