/**
 * The stable, user-mappable error surface the shells receive across the FFI.
 */
sealed class ApiException: kotlin.Exception() {
    
    /**
     * The source's server could not be reached.
     */
    class NetworkUnreachable(
        ) : ApiException() {
        override val message
            get() = ""
    }
    
    /**
     * A request took too long.
     */
    class Timeout(
        ) : ApiException() {
        override val message
            get() = ""
    }
    
    /**
     * The source rejected the supplied credentials.
     */
    class Unauthorized(
        ) : ApiException() {
        override val message
            get() = ""
    }
    
    /**
     * The requested item no longer exists at the source.
     */
    class NotFound(
        ) : ApiException() {
        override val message
            get() = ""
    }
    
    /**
     * Input provided by the user was not usable.
     */
    class InvalidInput(
        
        /**
         * A short, plain-language reason (never contains secret material).
         */
        val `reason`: kotlin.String
        ) : ApiException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    /**
     * The response was fetched but yielded no usable channels.
     */
    class ParseFailed(
        
        /**
         * Channels successfully read.
         */
        val `emitted`: kotlin.ULong, 
        
        /**
         * Entries skipped as malformed.
         */
        val `skipped`: kotlin.ULong
        ) : ApiException() {
        override val message
            get() = "emitted=${ `emitted` }, skipped=${ `skipped` }"
    }
    
    /**
     * The local database could not be read or written.
     */
    class StorageCorrupt(
        ) : ApiException() {
        override val message
            get() = ""
    }
    
    /**
     * The operation was cancelled (by the user or a departing screen).
     */
    class Cancelled(
        ) : ApiException() {
        override val message
            get() = ""
    }
    
    /**
     * An unexpected internal error; the detail is in the log stream.
     */
    class Internal(
        ) : ApiException() {
        override val message
            get() = ""
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<ApiException> {
        override fun lift(error_buf: RustBuffer.ByValue): ApiException = FfiConverterTypeApiError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeApiError : FfiConverterRustBuffer<ApiException> {
    override fun read(buf: ByteBuffer): ApiException {
        

        return when(buf.getInt()) {
            1 -> ApiException.NetworkUnreachable()
            2 -> ApiException.Timeout()
            3 -> ApiException.Unauthorized()
            4 -> ApiException.NotFound()
            5 -> ApiException.InvalidInput(
                FfiConverterString.read(buf),
                )
            6 -> ApiException.ParseFailed(
                FfiConverterULong.read(buf),
                FfiConverterULong.read(buf),
                )
            7 -> ApiException.StorageCorrupt()
            8 -> ApiException.Cancelled()
            9 -> ApiException.Internal()
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: ApiException): ULong {
        return when(value) {
            is ApiException.NetworkUnreachable -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ApiException.Timeout -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ApiException.Unauthorized -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ApiException.NotFound -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ApiException.InvalidInput -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is ApiException.ParseFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterULong.allocationSize(value.`emitted`)
                + FfiConverterULong.allocationSize(value.`skipped`)
            )
            is ApiException.StorageCorrupt -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ApiException.Cancelled -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ApiException.Internal -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: ApiException, buf: ByteBuffer) {
        when(value) {
            is ApiException.NetworkUnreachable -> {
                buf.putInt(1)
                Unit
            }
            is ApiException.Timeout -> {
                buf.putInt(2)
                Unit
            }
            is ApiException.Unauthorized -> {
                buf.putInt(3)
                Unit
            }
            is ApiException.NotFound -> {
                buf.putInt(4)
                Unit
            }
            is ApiException.InvalidInput -> {
                buf.putInt(5)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is ApiException.ParseFailed -> {
                buf.putInt(6)
                FfiConverterULong.write(value.`emitted`, buf)
                FfiConverterULong.write(value.`skipped`, buf)
                Unit
            }
            is ApiException.StorageCorrupt -> {
                buf.putInt(7)
                Unit
            }
            is ApiException.Cancelled -> {
                buf.putInt(8)
                Unit
            }
            is ApiException.Internal -> {
                buf.putInt(9)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



